import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function VideoPlayerPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [video, setVideo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [liked, setLiked] = useState(false);
  const [commentText, setCommentText] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [viewRecorded, setViewRecorded] = useState(false);

  const getToken = () => localStorage.getItem('access');
  const getCurrentUser = () => {
    const token = getToken();
    if (!token) return null;
    try {
      const payload = JSON.parse(atob(token.split('.')[1]));
      return payload.username;
    } catch (e) {
      return null;
    }
  };

  useEffect(() => {
    fetchVideo();
  }, [id]);

  const fetchVideo = async () => {
    try {
      const response = await axios.get(`http://localhost:8000/api/videos/${id}/`);
      setVideo(response.data);
      setLiked(response.data.user_has_liked || false);
      setLoading(false);
      
      // Записываем просмотр (только один раз)
      if (!viewRecorded) {
        await axios.post(`http://localhost:8000/api/videos/${id}/increment_views/`);
        setViewRecorded(true);
      }
    } catch (error) {
      console.error('Ошибка:', error);
      setError('Видео не найдено');
      setLoading(false);
    }
  };

  const handleLike = async () => {
    const token = getToken();
    if (!token) {
      navigate('/login');
      return;
    }
    try {
      const response = await axios.post(`http://localhost:8000/api/videos/${id}/like/`, {}, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      setLiked(response.data.liked);
      setVideo(prev => ({ ...prev, likes_count: response.data.likes_count }));
    } catch (error) {
      console.error('Ошибка лайка:', error);
    }
  };

  const handleComment = async (e) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    
    const token = getToken();
    if (!token) {
      navigate('/login');
      return;
    }
    
    setSubmitting(true);
    try {
      const response = await axios.post(`http://localhost:8000/api/videos/${id}/comment/`, 
        { text: commentText },
        { headers: { 'Authorization': `Bearer ${token}` } }
      );
      setVideo(prev => ({
        ...prev,
        comments: [response.data, ...(prev.comments || [])],
        comments_count: (prev.comments_count || 0) + 1
      }));
      setCommentText('');
    } catch (error) {
      console.error('Ошибка комментария:', error);
      alert('Не удалось отправить комментарий');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!window.confirm('Вы уверены, что хотите удалить это видео?')) return;
    
    const token = getToken();
    if (!token) {
      navigate('/login');
      return;
    }
    
    try {
      await axios.delete(`http://localhost:8000/api/videos/${id}/`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      alert('✅ Видео удалено');
      navigate('/');
    } catch (error) {
      console.error('Ошибка удаления:', error);
      alert('❌ Не удалось удалить видео');
    }
  };

  if (loading) {
    return (
      <div style={{ textAlign: 'center', marginTop: 50, fontSize: 18, color: '#666' }}>
        ⏳ Загрузка видео...
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ textAlign: 'center', marginTop: 50, fontSize: 18, color: 'red' }}>
        ❌ {error}
      </div>
    );
  }

  if (!video) {
    return (
      <div style={{ textAlign: 'center', marginTop: 50, fontSize: 18, color: '#666' }}>
        📭 Видео не найдено
      </div>
    );
  }

  const videoUrl = `http://localhost:8000/api/videos/${id}/stream/`;
  const currentUser = getCurrentUser();
  const isAuthor = currentUser === video.uploaded_by_name;

  return (
    <div style={{ maxWidth: 1000, margin: '0 auto', padding: '0 20px' }}>
      {/* Видео плеер */}
      <div style={{
        backgroundColor: '#000',
        borderRadius: 16,
        overflow: 'hidden',
        boxShadow: '0 4px 20px rgba(0,0,0,0.1)'
      }}>
        <video
          src={videoUrl}
          controls
          autoPlay
          style={{ width: '100%', display: 'block' }}
        />
      </div>

      {/* Информация о видео */}
      <div style={{ marginTop: 24 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', flexWrap: 'wrap', gap: 16 }}>
          <div style={{ flex: 1 }}>
            <h1 style={{ fontSize: 24, marginBottom: 8, color: '#1a1a1a' }}>{video.title}</h1>
            <div style={{ display: 'flex', gap: 16, color: '#6c757d', fontSize: 14, marginBottom: 12 }}>
              <span>👤 {video.uploaded_by_name}</span>
              <span>👁️ {video.views} просмотров</span>
              <span>❤️ {video.likes_count || 0} лайков</span>
            </div>
            <p style={{ color: '#555', lineHeight: 1.6, marginBottom: 16 }}>
              {video.description || 'Нет описания'}
            </p>
          </div>
          
          <div style={{ display: 'flex', gap: 12 }}>
            {/* Кнопка лайка */}
            <button
              onClick={handleLike}
              style={{
                background: 'none',
                border: 'none',
                fontSize: 18,
                cursor: 'pointer',
                padding: '8px 16px',
                borderRadius: 20,
                backgroundColor: liked ? '#fee2e2' : '#f0f4ff',
                color: liked ? '#ef4444' : '#4361ee',
                display: 'flex',
                alignItems: 'center',
                gap: 6,
                transition: 'all 0.2s'
              }}
            >
              {liked ? '❤️' : '🤍'} {video.likes_count || 0}
            </button>
            
            {/* Кнопка удаления (только для автора) */}
            {isAuthor && (
              <button
                onClick={handleDelete}
                style={{
                  background: '#ef4444',
                  color: 'white',
                  border: 'none',
                  padding: '8px 20px',
                  borderRadius: 20,
                  cursor: 'pointer',
                  fontSize: 14,
                  fontWeight: 500,
                  transition: 'all 0.2s'
                }}
                onMouseEnter={(e) => e.target.style.backgroundColor = '#dc2626'}
                onMouseLeave={(e) => e.target.style.backgroundColor = '#ef4444'}
              >
                🗑️ Удалить
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Комментарии */}
      <div style={{ marginTop: 40 }}>
        <h3 style={{ fontSize: 20, marginBottom: 20, color: '#1a1a1a' }}>
          💬 Комментарии ({video.comments_count || 0})
        </h3>
        
        {/* Форма добавления комментария */}
        <form onSubmit={handleComment} style={{ display: 'flex', gap: 12, marginBottom: 24 }}>
          <input
            type="text"
            placeholder="Напишите комментарий..."
            value={commentText}
            onChange={(e) => setCommentText(e.target.value)}
            style={{
              flex: 1,
              padding: '12px 16px',
              border: '1px solid #e9ecef',
              borderRadius: 24,
              fontSize: 14,
              outline: 'none',
              transition: 'border-color 0.2s'
            }}
            onFocus={(e) => e.target.style.borderColor = '#4361ee'}
            onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
          />
          <button
            type="submit"
            disabled={submitting || !commentText.trim()}
            style={{
              background: '#4361ee',
              color: 'white',
              border: 'none',
              padding: '0 24px',
              borderRadius: 24,
              cursor: (submitting || !commentText.trim()) ? 'not-allowed' : 'pointer',
              fontSize: 14,
              fontWeight: 500,
              opacity: (submitting || !commentText.trim()) ? 0.6 : 1
            }}
          >
            {submitting ? '...' : 'Отправить'}
          </button>
        </form>
        
        {/* Список комментариев */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {video.comments && video.comments.length > 0 ? (
            video.comments.map(comment => (
              <div key={comment.id} style={{
                padding: '12px 16px',
                backgroundColor: '#f8f9fa',
                borderRadius: 16,
                transition: 'background-color 0.2s'
              }}>
                <div style={{ fontWeight: 600, marginBottom: 6, color: '#1a1a1a' }}>
                  {comment.username}
                </div>
                <p style={{ margin: 0, color: '#333', fontSize: 14, lineHeight: 1.5 }}>
                  {comment.text}
                </p>
                <div style={{ fontSize: 11, color: '#aaa', marginTop: 8 }}>
                  {new Date(comment.created_at).toLocaleString()}
                </div>
              </div>
            ))
          ) : (
            <div style={{
              textAlign: 'center',
              padding: 48,
              backgroundColor: '#f8f9fa',
              borderRadius: 16,
              color: '#aaa'
            }}>
              💬 Пока нет комментариев. Будьте первым!
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default VideoPlayerPage;
